import{_ as i,o,c as e,ai as c}from"./chunks/framework.CsYGeNYI.js";const f=JSON.parse('{"title":"严格配置验证","description":"","frontmatter":{"read_when":["设计或实现配置验证行为","处理配置迁移或 doctor 工作流","处理插件配置 schema 或插件加载门控"],"summary":"严格配置验证 + 仅通过 doctor 进行迁移","title":"严格配置验证","x-i18n":{"generated_at":"2026-02-03T10:08:51Z","model":"claude-opus-4-5","provider":"pi","source_hash":"5bc7174a67d2234e763f21330d8fe3afebc23b2e5c728a04abcc648b453a91cc","source_path":"refactor/strict-config.md","workflow":15}},"headers":[],"relativePath":"zh-CN/refactor/strict-config.md","filePath":"zh-CN/refactor/strict-config.md","lastUpdated":1771906665000}'),a={name:"zh-CN/refactor/strict-config.md"};function d(r,l,s,t,n,h){return o(),e("div",null,[...l[0]||(l[0]=[c('<h1 id="严格配置验证-仅通过-doctor-进行迁移" tabindex="-1"><a class="header-anchor" href="#严格配置验证-仅通过-doctor-进行迁移">#</a> 严格配置验证（仅通过 doctor 进行迁移）</h1><h2 id="目标" tabindex="-1"><a class="header-anchor" href="#目标">#</a> 目标</h2><ul><li><strong>在所有地方拒绝未知配置键</strong>（根级 + 嵌套）。</li><li><strong>拒绝没有 schema 的插件配置</strong>；不加载该插件。</li><li><strong>移除加载时的旧版自动迁移</strong>；迁移仅通过 doctor 运行。</li><li><strong>启动时自动运行 doctor（dry-run）</strong>；如果无效，阻止非诊断命令。</li></ul><h2 id="非目标" tabindex="-1"><a class="header-anchor" href="#非目标">#</a> 非目标</h2><ul><li>加载时的向后兼容性（旧版键不会自动迁移）。</li><li>静默丢弃无法识别的键。</li></ul><h2 id="严格验证规则" tabindex="-1"><a class="header-anchor" href="#严格验证规则">#</a> 严格验证规则</h2><ul><li>配置必须在每个层级精确匹配 schema。</li><li>未知键是验证错误（根级或嵌套都不允许透传）。</li><li><code>plugins.entries.&lt;id&gt;.config</code> 必须由插件的 schema 验证。 <ul><li>如果插件缺少 schema，<strong>拒绝插件加载</strong>并显示清晰的错误。</li></ul></li><li>未知的 <code>channels.&lt;id&gt;</code> 键是错误，除非插件清单声明了该渠道 id。</li><li>所有插件都需要插件清单（<code>opensoul.plugin.json</code>）。</li></ul><h2 id="插件-schema-强制执行" tabindex="-1"><a class="header-anchor" href="#插件-schema-强制执行">#</a> 插件 schema 强制执行</h2><ul><li>每个插件为其配置提供严格的 JSON Schema（内联在清单中）。</li><li>插件加载流程： <ol><li>解析插件清单 + schema（<code>opensoul.plugin.json</code>）。</li><li>根据 schema 验证配置。</li><li>如果缺少 schema 或配置无效：阻止插件加载，记录错误。</li></ol></li><li>错误消息包括： <ul><li>插件 id</li><li>原因（缺少 schema / 配置无效）</li><li>验证失败的路径</li></ul></li><li>禁用的插件保留其配置，但 Doctor + 日志会显示警告。</li></ul><h2 id="doctor-流程" tabindex="-1"><a class="header-anchor" href="#doctor-流程">#</a> Doctor 流程</h2><ul><li>每次加载配置时都会运行 Doctor（默认 dry-run）。</li><li>如果配置无效： <ul><li>打印摘要 + 可操作的错误。</li><li>指示：<code>opensoul doctor --fix</code>。</li></ul></li><li><code>opensoul doctor --fix</code>： <ul><li>应用迁移。</li><li>移除未知键。</li><li>写入更新后的配置。</li></ul></li></ul><h2 id="命令门控-当配置无效时" tabindex="-1"><a class="header-anchor" href="#命令门控-当配置无效时">#</a> 命令门控（当配置无效时）</h2><p>允许的命令（仅诊断）：</p><ul><li><code>opensoul doctor</code></li><li><code>opensoul logs</code></li><li><code>opensoul health</code></li><li><code>opensoul help</code></li><li><code>opensoul status</code></li><li><code>opensoul gateway status</code></li></ul><p>其他所有命令必须硬失败并显示：&quot;Config invalid. Run <code>opensoul doctor --fix</code>.&quot;</p><h2 id="错误用户体验格式" tabindex="-1"><a class="header-anchor" href="#错误用户体验格式">#</a> 错误用户体验格式</h2><ul><li>单个摘要标题。</li><li>分组部分： <ul><li>未知键（完整路径）</li><li>旧版键/需要迁移</li><li>插件加载失败（插件 id + 原因 + 路径）</li></ul></li></ul><h2 id="实现接触点" tabindex="-1"><a class="header-anchor" href="#实现接触点">#</a> 实现接触点</h2><ul><li><code>src/config/zod-schema.ts</code>：移除根级透传；所有地方使用严格对象。</li><li><code>src/config/zod-schema.providers.ts</code>：确保严格的渠道 schema。</li><li><code>src/config/validation.ts</code>：未知键时失败；不应用旧版迁移。</li><li><code>src/config/io.ts</code>：移除旧版自动迁移；始终运行 doctor dry-run。</li><li><code>src/config/legacy*.ts</code>：将用法移至仅 doctor。</li><li><code>src/plugins/*</code>：添加 schema 注册表 + 门控。</li><li><code>src/cli</code> 中的 CLI 命令门控。</li></ul><h2 id="测试" tabindex="-1"><a class="header-anchor" href="#测试">#</a> 测试</h2><ul><li>未知键拒绝（根级 + 嵌套）。</li><li>插件缺少 schema → 插件加载被阻止并显示清晰错误。</li><li>无效配置 → Gateway 网关启动被阻止，诊断命令除外。</li><li>Doctor dry-run 自动运行；<code>doctor --fix</code> 写入修正后的配置。</li></ul>',21)])])}const p=i(a,[["render",d]]);export{f as __pageData,p as default};
